class Solution:
    def maxAbsValExpr(self, arr1, arr2):
        n = len(arr1)
        best = 0
        for i in range(n):
            for j in range(i, n):
                v = abs(arr1[i] - arr1[j]) + abs(arr2[i] - arr2[j]) + abs(i - j)
                if v > best:
                    best = v
        return best

