class Solution:
    def maxAbsValExpr(self, arr1, arr2):
        n = len(arr1)
        best = 0
        for s1 in (1, -1):
            for s2 in (1, -1):
                hi = float('-inf')
                lo = float('inf')
                for k in range(n):
                    val = s1 * arr1[k] + s2 * arr2[k] + k
                    hi = max(hi, val)
                    lo = min(lo, val)
                best = max(best, hi - lo)
        return best

