var maxAbsValExpr = function(arr1, arr2) {
    const n = arr1.length;
    let best = 0;
    for (const s1 of [1, -1]) {
        for (const s2 of [1, -1]) {
            let hi = -Infinity, lo = Infinity;
            for (let k = 0; k < n; k++) {
                const val = s1 * arr1[k] + s2 * arr2[k] + k;
                if (val > hi) hi = val;
                if (val < lo) lo = val;
            }
            best = Math.max(best, hi - lo);
        }
    }
    return best;
};
